import { readdir, readFile, stat, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { pathToFileURL } from 'node:url';

const root = process.cwd();
const outputFile = path.join(root, 'project.bundle.mjs');
const ignoredDirectories = new Set(['.git', 'node_modules', 'dist', '.playwright-cli', 'coverage', 'restored-project']);
const ignoredFiles = new Set(['project.bundle.mjs', '.DS_Store']);

async function collectFiles(directory) {
  const entries = await readdir(directory, { withFileTypes: true });
  const files = [];

  for (const entry of entries) {
    if (entry.isDirectory() && ignoredDirectories.has(entry.name)) {
      continue;
    }

    const absolutePath = path.join(directory, entry.name);
    const relativePath = path.relative(root, absolutePath).split(path.sep).join('/');

    if (entry.isDirectory()) {
      files.push(...(await collectFiles(absolutePath)));
      continue;
    }

    if (!entry.isFile() || ignoredFiles.has(entry.name)) {
      continue;
    }

    const fileStat = await stat(absolutePath);
    const content = await readFile(absolutePath);
    files.push({
      path: relativePath,
      mode: fileStat.mode & 0o777,
      encoding: 'base64',
      content: content.toString('base64'),
    });
  }

  return files;
}

const files = (await collectFiles(root)).sort((a, b) => a.path.localeCompare(b.path));
const bundle = {
  version: 1,
  name: 'mui-flow-admin',
  generatedAt: new Date().toISOString(),
  files,
};

const source = `// Generated by scripts/create-project-bundle.mjs.
// Restore with: node scripts/restore-project.mjs project.bundle.mjs restored-project --force

import { pathToFileURL } from 'node:url';

export const projectBundle = ${JSON.stringify(bundle, null, 2)};

if (process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href) {
  const totalBytes = projectBundle.files.reduce((sum, file) => sum + Buffer.from(file.content, 'base64').byteLength, 0);
  console.log(\`\${projectBundle.name}: \${projectBundle.files.length} files, \${totalBytes} bytes\`);
}
`;

await writeFile(outputFile, source);
console.log(`Wrote ${path.relative(root, outputFile)} with ${files.length} files.`);
